CREATE TYPE "Surface" AS ENUM ('WEB','MOBILE');
CREATE TYPE "ItemKind" AS ENUM ('APPLICATION','WIDGET');
CREATE TYPE "WidgetType" AS ENUM ('SYSTEM','STORAGE','NETWORK','CLOCK','WEATHER','SEARCH','STATUS','PROMQL');
CREATE TABLE "User" ("id" TEXT PRIMARY KEY,"username" TEXT NOT NULL UNIQUE,"passwordHash" TEXT NOT NULL,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL);
CREATE TABLE "Session" ("id" TEXT PRIMARY KEY,"tokenHash" TEXT NOT NULL UNIQUE,"expiresAt" TIMESTAMP(3) NOT NULL,"userId" TEXT NOT NULL,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE "Dashboard" ("id" TEXT PRIMARY KEY,"name" TEXT NOT NULL DEFAULT 'Meu DashLab',"branding" JSONB NOT NULL,"userId" TEXT NOT NULL UNIQUE,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL);
CREATE TABLE "Application" ("id" TEXT PRIMARY KEY,"name" TEXT NOT NULL,"description" TEXT,"url" TEXT NOT NULL,"deepLink" TEXT,"icon" TEXT,"category" TEXT,"statusUrl" TEXT,"inDock" BOOLEAN NOT NULL DEFAULT false,"visible" BOOLEAN NOT NULL DEFAULT true,"dashboardId" TEXT NOT NULL,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL);
CREATE TABLE "Widget" ("id" TEXT PRIMARY KEY,"type" "WidgetType" NOT NULL,"title" TEXT NOT NULL,"config" JSONB NOT NULL,"visible" BOOLEAN NOT NULL DEFAULT true,"dashboardId" TEXT NOT NULL,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL);
CREATE TABLE "LayoutItem" ("id" TEXT PRIMARY KEY,"surface" "Surface" NOT NULL,"kind" "ItemKind" NOT NULL,"x" INTEGER NOT NULL DEFAULT 0,"y" INTEGER NOT NULL DEFAULT 0,"w" INTEGER NOT NULL DEFAULT 1,"h" INTEGER NOT NULL DEFAULT 1,"order" INTEGER NOT NULL DEFAULT 0,"dashboardId" TEXT NOT NULL,"applicationId" TEXT,"widgetId" TEXT);
CREATE TABLE "Asset" ("id" TEXT PRIMARY KEY,"name" TEXT NOT NULL,"mimeType" TEXT NOT NULL,"path" TEXT NOT NULL,"dashboardId" TEXT NOT NULL,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE INDEX "Application_dashboardId_idx" ON "Application"("dashboardId");
CREATE INDEX "Widget_dashboardId_idx" ON "Widget"("dashboardId");
CREATE INDEX "LayoutItem_dashboardId_surface_idx" ON "LayoutItem"("dashboardId","surface");
CREATE INDEX "Asset_dashboardId_idx" ON "Asset"("dashboardId");
ALTER TABLE "Session" ADD CONSTRAINT "Session_userId_fkey" FOREIGN KEY("userId") REFERENCES "User"("id") ON DELETE CASCADE ON UPDATE CASCADE;
ALTER TABLE "Dashboard" ADD CONSTRAINT "Dashboard_userId_fkey" FOREIGN KEY("userId") REFERENCES "User"("id") ON DELETE CASCADE ON UPDATE CASCADE;
ALTER TABLE "Application" ADD CONSTRAINT "Application_dashboardId_fkey" FOREIGN KEY("dashboardId") REFERENCES "Dashboard"("id") ON DELETE CASCADE ON UPDATE CASCADE;
ALTER TABLE "Widget" ADD CONSTRAINT "Widget_dashboardId_fkey" FOREIGN KEY("dashboardId") REFERENCES "Dashboard"("id") ON DELETE CASCADE ON UPDATE CASCADE;
ALTER TABLE "LayoutItem" ADD CONSTRAINT "LayoutItem_dashboardId_fkey" FOREIGN KEY("dashboardId") REFERENCES "Dashboard"("id") ON DELETE CASCADE ON UPDATE CASCADE;
ALTER TABLE "LayoutItem" ADD CONSTRAINT "LayoutItem_applicationId_fkey" FOREIGN KEY("applicationId") REFERENCES "Application"("id") ON DELETE CASCADE ON UPDATE CASCADE;
ALTER TABLE "LayoutItem" ADD CONSTRAINT "LayoutItem_widgetId_fkey" FOREIGN KEY("widgetId") REFERENCES "Widget"("id") ON DELETE CASCADE ON UPDATE CASCADE;
ALTER TABLE "Asset" ADD CONSTRAINT "Asset_dashboardId_fkey" FOREIGN KEY("dashboardId") REFERENCES "Dashboard"("id") ON DELETE CASCADE ON UPDATE CASCADE;
